 20→#[derive(Debug, Default)]
 21→struct TestProvider;
 22→
 23→#[async_trait]
 24→impl ModelProviderPort for TestProvider {
 25→    async fn complete(&self, request: ModelCompletionRequest) -> KernelResult<ModelCompletion> {
 26→        Ok(ModelCompletion {
 27→            provider: "test".to_owned(),
 28→            model: "test-model".to_owned(),
 29→            directives: vec![ModelDirective::Message {
 30→                role: "assistant".to_owned(),
