 40→fn unique_root(name: &str) -> PathBuf {
 41→    let nanos = SystemTime::now()
 42→        .duration_since(UNIX_EPOCH)
 43→        .map(|duration| duration.as_nanos())
 44→        .unwrap_or(0);
 45→    std::env::temp_dir().join(format!("{name}-{nanos}"))
 46→}
 47→
 48→fn build_runtime(root: PathBuf) -> Arc<KernelRuntime> {
 49→    let event_store_backend = Arc::new(FileEventStore::new(root.join("kernel")));
 50→    let journal = Arc::new(EventJournal::new(
 51→        event_store_backend,
 52→        EventStreamHub::new(1024),
 53→    ));
 54→    let event_store: Arc<dyn EventStorePort> = journal;
 55→
 56→    let policy_engine = Arc::new(SessionPolicyEngine::new(PolicySet::default()));
 57→    let policy_gate: Arc<dyn PolicyGatePort> = policy_engine.clone();
 58→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ApprovalQueue::default());
 59→
 60→    let registry = Arc::new(ToolRegistry::with_core_tools());
 61→    let sandbox = Arc::new(LocalSandboxRunner::new(vec!["echo".to_owned()]));
 62→    let dispatcher = Arc::new(ToolDispatcher::new(registry, policy_engine, sandbox));
 63→    let tool_harness: Arc<dyn ToolHarnessPort> = dispatcher;
 64→
 65→    let provider: Arc<dyn ModelProviderPort> = Arc::new(TestProvider);
 66→
 67→    Arc::new(KernelRuntime::new(
 68→        RuntimeConfig::new(root),
 69→        event_store,
 70→        provider,
 71→        tool_harness,
 72→        approvals,
 73→        policy_gate,
 74→    ))
 75→}
