213→    engine.add_rule(Rule {
214→        id: "deny-shell".into(),
215→        name: "Deny shell".into(),
216→        priority: 10,
217→        condition: MatchCondition::ToolName("exec_shell".into()),
218→        decision: PolicyDecisionKind::Deny,
219→        explanation: Some("Shell execution not permitted".into()),
220→        required_sandbox: None,
221→    });
222→    engine.add_rule(Rule {
223→        id: "approve-critical".into(),
224→        name: "Approve critical".into(),
225→        priority: 20,
226→        condition: MatchCondition::RiskAtLeast(lago_core::event::RiskLevel::Critical),
227→        decision: PolicyDecisionKind::RequireApproval,
228→        explanation: None,
229→        required_sandbox: None,
230→    });
231→    engine.add_rule(Rule {
232→        id: "allow-filesystem".into(),
233→        name: "Allow filesystem".into(),
234→        priority: 50,
235→        condition: MatchCondition::ToolPattern("file_*".into()),
236→        decision: PolicyDecisionKind::Allow,
237→        explanation: None,
238→        required_sandbox: None,
239→    });
240→    engine.add_rule(Rule {
241→        id: "default-allow".into(),
242→        name: "Default allow".into(),
243→        priority: 1000,
244→        condition: MatchCondition::Always,
245→        decision: PolicyDecisionKind::Allow,
246→        explanation: None,
247→        required_sandbox: None,
248→    });
249→
250→    let mut annotations = HashMap::new();
251→    annotations.insert(
252→        "exec_shell".to_string(),
253→        ToolAnnotations {
254→            read_only: false,
255→            destructive: true,
256→            idempotent: false,
257→            open_world: true,
258→            requires_confirmation: true,
259→        },
260→    );
261→    annotations.insert(
262→        "file_read".to_string(),
263→        ToolAnnotations {
264→            read_only: true,
265→            destructive: false,
266→            idempotent: true,
267→            open_world: false,
268→            requires_confirmation: false,
269→        },
270→    );
271→    annotations.insert(
272→        "file_write".to_string(),
273→        ToolAnnotations {
274→            read_only: false,
275→            destructive: true,
276→            idempotent: false,
277→            open_world: false,
278→            requires_confirmation: false,
279→        },
280→    );
281→
282→    let middleware = LagoPolicyMiddleware::new(engine, annotations);
283→    let ctx = ToolContext {
284→        run_id: "r1".into(),
285→        session_id: "s1".into(),
286→        iteration: 1,
287→    };
288→
289→    // Shell should be denied
290→    let shell_call = ToolCall {
291→        call_id: "c1".into(),
292→        tool_name: "exec_shell".into(),
293→        input: serde_json::json!({"command": "rm -rf /"}),
294→    };
295→    let result = middleware.pre_tool_call(&ctx, &shell_call);
296→    assert!(result.is_err(), "shell should be denied");
297→    assert!(
