370→            })
371→            .unwrap();
372→
373→            // Session 1 again
374→            repo.append(AppendEvent {
375→                session_id: "session-a".into(),
376→                branch_id: "main".into(),
377→                parent_id: None,
378→                event: AgentEvent::RunFinished {
379→                    run_id: "r1".into(),
380→                    session_id: "session-a".into(),
381→                    reason: RunStopReason::Completed,
382→                    total_iterations: 1,
383→                    final_answer: Some("done A".into()),
384→                },
385→            })
386→            .unwrap();
387→        }
388→    })
389→    .await
390→    .unwrap();
391→
392→    // Load session A
393→    let records_a = tokio::task::spawn_blocking({
394→        let repo = repo.clone();
395→        move || repo.load_session("session-a", "main").unwrap()
396→    })
397→    .await
398→    .unwrap();
399→    assert_eq!(records_a.len(), 2, "session-a should have 2 events");
400→
401→    // Load session B
402→    let records_b = tokio::task::spawn_blocking({
403→        let repo = repo.clone();
404→        move || repo.load_session("session-b", "main").unwrap()
405→    })
406→    .await
407→    .unwrap();
408→    assert_eq!(records_b.len(), 1, "session-b should have 1 event");
409→}
