 43→#[derive(Clone)]
 44→pub struct LagoAiosEventStoreAdapter {
 45→    journal: Arc<dyn Journal>,
 46→}
 47→
 48→impl LagoAiosEventStoreAdapter {
 49→    pub fn new(journal: Arc<dyn Journal>) -> Self {
 50→        Self { journal }
 51→    }
 52→}
 53→
 54→#[async_trait]
 55→impl EventStorePort for LagoAiosEventStoreAdapter {
 56→    async fn append(&self, event: EventRecord) -> Result<EventRecord, KernelError> {
 57→        let protocol_envelope = event.to_envelope();
 58→        let lago_envelope =
 59→            protocol_bridge::from_protocol(&protocol_envelope).ok_or_else(|| {
 60→                KernelError::Serialization("failed converting protocol envelope".to_owned())
 61→            })?;
 62→        let assigned_seq = self
 63→            .journal
 64→            .append(lago_envelope)
 65→            .await
 66→            .map_err(to_kernel_error)?;
 67→
 68→        let mut persisted = event;
 69→        persisted.sequence = assigned_seq;
 70→        Ok(persisted)
 71→    }
 72→
 73→    async fn read(
 74→        &self,
 75→        session_id: ProtocolSessionId,
 76→        branch_id: ProtocolBranchId,
 77→        from_sequence: u64,
 78→        limit: usize,
 79→    ) -> Result<Vec<EventRecord>, KernelError> {
 80→        let query = EventQuery::new()
 81→            .session(session_id.into())
 82→            .branch(branch_id.into())
 83→            .after(from_sequence.saturating_sub(1))
 84→            .limit(limit);
 85→        let events = self.journal.read(query).await.map_err(to_kernel_error)?;
 86→
 87→        events
 88→            .into_iter()
 89→            .map(|envelope| {
 90→                let protocol = envelope.to_protocol().ok_or_else(|| {
 91→                    KernelError::Serialization("failed converting lago envelope".to_owned())
 92→                })?;
 93→                envelope_to_record(protocol)
 94→            })
 95→            .collect()
 96→    }
 97→
 98→    async fn head(
 99→        &self,
100→        session_id: ProtocolSessionId,
101→        branch_id: ProtocolBranchId,
102→    ) -> Result<u64, KernelError> {
103→        self.journal
104→            .head_seq(&session_id.into(), &branch_id.into())
105→            .await
106→            .map_err(to_kernel_error)
107→    }
108→
109→    async fn subscribe(
110→        &self,
111→        session_id: ProtocolSessionId,
112→        branch_id: ProtocolBranchId,
113→        after_sequence: u64,
114→    ) -> Result<EventRecordStream, KernelError> {
115→        let stream = self
116→            .journal
117→            .stream(
118→                session_id.clone().into(),
119→                branch_id.clone().into(),
120→                after_sequence,
121→            )
122→            .await
123→            .map_err(to_kernel_error)?;
124→
125→        let adapted = stream.filter_map(|item| async move {
126→            match item {
127→                Ok(envelope) => {
128→                    let protocol = match envelope.to_protocol() {
129→                        Some(protocol) => protocol,
130→                        None => {
131→                            warn!("failed converting lago event envelope to protocol");
132→                            return Some(Err(KernelError::Serialization(
133→                                "failed converting lago envelope".to_owned(),
134→                            )));
135→                        }
136→                    };
137→                    Some(envelope_to_record(protocol))
138→                }
139→                Err(error) => Some(Err(to_kernel_error(error))),
140→            }
141→        });
142→
143→        Ok(Box::pin(adapted) as BoxStream<'static, Result<EventRecord, KernelError>>)
144→    }
145→}
