  1→//! RedbJournal — the primary Journal trait implementation backed by redb.
  2→
  3→use std::collections::HashMap;
  4→use std::path::Path;
  5→use std::sync::Arc;
  6→
  7→use redb::{Database, ReadableTable};
  8→use tokio::sync::broadcast;
  9→use tracing::debug;
 10→
 11→use lago_core::{
 12→    BranchId, EventEnvelope, EventId, EventQuery, EventStream, Journal, LagoError, LagoResult,
 13→    SeqNo, Session, SessionId,
 14→};
 15→
 16→use crate::keys::{encode_branch_key, encode_event_key};
 17→use crate::stream::EventTailStream;
 18→use crate::tables::{BRANCH_HEADS, EVENT_INDEX, EVENTS, SESSIONS, SNAPSHOTS};
 19→
 20→/// Notification payload broadcast when new events are appended.
 21→#[derive(Debug, Clone)]
 22→pub struct EventNotification {
 23→    pub session_id: SessionId,
 24→    pub branch_id: BranchId,
 25→    pub seq: SeqNo,
 26→}
 27→
 28→/// An event journal backed by redb — an embedded, ACID, key-value store.
 29→///
 30→/// All redb operations are run on a blocking thread pool via
 31→/// `tokio::task::spawn_blocking` because redb is synchronous.
 32→#[derive(Clone)]
 33→pub struct RedbJournal {
 34→    db: Arc<Database>,
 35→    notify_tx: broadcast::Sender<EventNotification>,
 36→}
 37→
 38→impl RedbJournal {
 39→    /// Open (or create) a journal database at the given filesystem path.
 40→    ///
 41→    /// Creates all required tables if they do not already exist.
 42→    pub fn open(path: impl AsRef<Path>) -> LagoResult<Self> {
 43→        let db = Database::create(path.as_ref())
 44→            .map_err(|e| LagoError::Journal(format!("failed to open redb database: {e}")))?;
 45→
 46→        // Ensure all tables exist by opening a write transaction.
 47→        {
 48→            let txn = db.begin_write().map_err(|e| {
 49→                LagoError::Journal(format!("failed to begin write txn for table init: {e}"))
 50→            })?;
 51→            txn.open_table(EVENTS)
 52→                .map_err(|e| LagoError::Journal(format!("failed to open events table: {e}")))?;
 53→            txn.open_table(EVENT_INDEX).map_err(|e| {
 54→                LagoError::Journal(format!("failed to open event_index table: {e}"))
 55→            })?;
 56→            txn.open_table(BRANCH_HEADS).map_err(|e| {
 57→                LagoError::Journal(format!("failed to open branch_heads table: {e}"))
 58→            })?;
 59→            txn.open_table(SESSIONS)
 60→                .map_err(|e| LagoError::Journal(format!("failed to open sessions table: {e}")))?;
 61→            txn.open_table(SNAPSHOTS)
 62→                .map_err(|e| LagoError::Journal(format!("failed to open snapshots table: {e}")))?;
 63→            txn.commit()
 64→                .map_err(|e| LagoError::Journal(format!("failed to commit table init: {e}")))?;
 65→        }
 66→
 67→        let (notify_tx, _) = broadcast::channel(4096);
 68→        Ok(Self {
 69→            db: Arc::new(db),
 70→            notify_tx,
 71→        })
 72→    }
 73→
 74→    /// Get a broadcast receiver for event notifications.
 75→    pub fn subscribe(&self) -> broadcast::Receiver<EventNotification> {
 76→        self.notify_tx.subscribe()
 77→    }
 78→
 79→    /// Get a reference to the underlying database.
 80→    pub fn db(&self) -> &Arc<Database> {
 81→        &self.db
 82→    }
 83→
 84→    // ---  Internal helpers (blocking, run on spawn_blocking)
 85→
 86→    /// Append a batch of events inside a single redb write transaction.
 87→    /// Returns the last assigned sequence number.
 88→    fn append_batch_blocking(
 89→        db: &Database,
 90→        events: Vec<EventEnvelope>,
 91→    ) -> LagoResult<(SeqNo, Vec<EventNotification>)> {
 92→        let txn = db
 93→            .begin_write()
 94→            .map_err(|e| LagoError::Journal(format!("begin_write failed: {e}")))?;
 95→
 96→        let mut last_seq = 0u64;
 97→        let mut notifications = Vec::with_capacity(events.len());
 98→        let mut branch_heads_cache: HashMap<Vec<u8>, SeqNo> = HashMap::new();
 99→
100→        {
101→            let mut events_table = txn
102→                .open_table(EVENTS)
103→                .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
104→            let mut index_table = txn
105→                .open_table(EVENT_INDEX)
106→                .map_err(|e| LagoError::Journal(format!("open event_index table: {e}")))?;
107→            let mut heads_table = txn
108→                .open_table(BRANCH_HEADS)
109→                .map_err(|e| LagoError::Journal(format!("open branch_heads table: {e}")))?;
110→
111→            for event in &events {
112→                let session_str = event.session_id.as_str();
113→                let branch_str = event.branch_id.as_str();
114→                let branch_key = encode_branch_key(session_str, branch_str);
115→                let current_head = if let Some(cached) = branch_heads_cache.get(&branch_key) {
116→                    *cached
117→                } else {
118→                    let head = heads_table
119→                        .get(branch_key.as_slice())
120→                        .map_err(|e| LagoError::Journal(format!("get branch head: {e}")))?
121→                        .map(|v| v.value())
122→                        .unwrap_or(0);
123→                    branch_heads_cache.insert(branch_key.clone(), head);
124→                    head
125→                };
126→                let assigned_seq = current_head.saturating_add(1);
127→                branch_heads_cache.insert(branch_key.clone(), assigned_seq);
128→
129→                let mut assigned_event = event.clone();
130→                assigned_event.seq = assigned_seq;
131→                // Serialize event to JSON
132→                let json = serde_json::to_string(&assigned_event)?;
133→
134→                // Encode compound key
135→                let event_key = encode_event_key(session_str, branch_str, assigned_seq);
136→
137→                // Write to events table
138→                events_table
139→                    .insert(event_key.as_slice(), json.as_str())
140→                    .map_err(|e| LagoError::Journal(format!("insert event: {e}")))?;
141→
142→                // Write to event index
143→                index_table
144→                    .insert(assigned_event.event_id.as_str(), event_key.as_slice())
145→                    .map_err(|e| LagoError::Journal(format!("insert event index: {e}")))?;
146→
147→                // Update branch head
148→                heads_table
149→                    .insert(branch_key.as_slice(), assigned_seq)
150→                    .map_err(|e| LagoError::Journal(format!("update branch head: {e}")))?;
151→
152→                last_seq = assigned_seq;
153→
154→                notifications.push(EventNotification {
155→                    session_id: assigned_event.session_id.clone(),
156→                    branch_id: assigned_event.branch_id.clone(),
157→                    seq: assigned_seq,
158→                });
159→            }
160→        }
161→
162→        txn.commit()
163→            .map_err(|e| LagoError::Journal(format!("commit failed: {e}")))?;
164→
165→        Ok((last_seq, notifications))
166→    }
167→
168→    /// Read events matching a query in a read transaction.
169→    fn read_blocking(db: &Database, query: EventQuery) -> LagoResult<Vec<EventEnvelope>> {
170→        let txn = db
171→            .begin_read()
172→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
173→        let events_table = txn
174→            .open_table(EVENTS)
175→            .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
176→
177→        let mut results = Vec::new();
178→
179→        // Build the key range based on query parameters
180→        match (&query.session_id, &query.branch_id) {
181→            (Some(session_id), Some(branch_id)) => {
182→                // Specific session + branch: scan within that prefix
183→                let after = query.after_seq.unwrap_or(0);
184→                let before = query.before_seq.unwrap_or(u64::MAX);
185→                let start_key = encode_event_key(session_id.as_str(), branch_id.as_str(), after);
186→                let end_key = encode_event_key(session_id.as_str(), branch_id.as_str(), before);
187→
188→                let range = events_table
189→                    .range(start_key.as_slice()..=end_key.as_slice())
190→                    .map_err(|e| LagoError::Journal(format!("range scan: {e}")))?;
191→
192→                for item in range {
193→                    let (_, value) =
194→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
195→                    let envelope: EventEnvelope = serde_json::from_str(value.value())?;
196→
197→                    // Filter: after_seq is exclusive
198→                    if let Some(after_seq) = query.after_seq
199→                        && envelope.seq <= after_seq
200→                    {
201→                        continue;
202→                    }
203→                    // Filter: before_seq is exclusive
204→                    if let Some(before_seq) = query.before_seq
205→                        && envelope.seq >= before_seq
206→                    {
207→                        continue;
208→                    }
209→
210→                    results.push(envelope);
211→                    if let Some(limit) = query.limit
212→                        && results.len() >= limit
213→                    {
214→                        break;
215→                    }
216→                }
217→            }
218→            (Some(session_id), None) => {
219→                // All branches for a session: scan the session prefix.
220→                // Start key = session_id + min_branch + 0
221→                // End key   = session_id + max_branch + u64::MAX
222→                let start_key = encode_event_key(session_id.as_str(), "", 0);
223→                // Use a key that is just past all valid branch IDs for this session
224→                let mut end_prefix = vec![0xFFu8; crate::keys::EVENT_KEY_LEN];
225→                let sid_bytes = session_id.as_str().as_bytes();
226→                let copy_len = sid_bytes.len().min(26);
227→                end_prefix[..copy_len].copy_from_slice(&sid_bytes[..copy_len]);
228→
229→                let range = events_table
230→                    .range(start_key.as_slice()..=end_prefix.as_slice())
231→                    .map_err(|e| LagoError::Journal(format!("range scan: {e}")))?;
232→
233→                for item in range {
234→                    let (_, value) =
235→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
236→                    let envelope: EventEnvelope = serde_json::from_str(value.value())?;
237→
238→                    if let Some(after_seq) = query.after_seq
239→                        && envelope.seq <= after_seq
240→                    {
241→                        continue;
242→                    }
243→                    if let Some(before_seq) = query.before_seq
244→                        && envelope.seq >= before_seq
245→                    {
246→                        continue;
247→                    }
248→
249→                    results.push(envelope);
250→                    if let Some(limit) = query.limit
251→                        && results.len() >= limit
252→                    {
253→                        break;
254→                    }
255→                }
256→            }
257→            (None, _) => {
258→                // Full scan (no session filter)
259→                let range = events_table
260→                    .iter()
261→                    .map_err(|e| LagoError::Journal(format!("iter: {e}")))?;
262→
263→                for item in range {
264→                    let (_key, value) =
265→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
266→                    let json_str: &str = value.value();
267→                    let envelope: EventEnvelope = serde_json::from_str(json_str)?;
268→
269→                    if let Some(ref sid) = query.session_id
270→                        && envelope.session_id.as_str() != sid.as_str()
271→                    {
272→                        continue;
273→                    }
274→                    if let Some(ref bid) = query.branch_id
275→                        && envelope.branch_id.as_str() != bid.as_str()
276→                    {
277→                        continue;
278→                    }
279→                    if let Some(after_seq) = query.after_seq
280→                        && envelope.seq <= after_seq
281→                    {
282→                        continue;
283→                    }
284→                    if let Some(before_seq) = query.before_seq
285→                        && envelope.seq >= before_seq
286→                    {
287→                        continue;
288→                    }
289→
290→                    results.push(envelope);
291→                    if let Some(limit) = query.limit
292→                        && results.len() >= limit
293→                    {
294→                        break;
295→                    }
296→                }
297→            }
298→        }
299→
300→        Ok(results)
301→    }
