356→    /// Put a session into the sessions table.
357→    fn put_session_blocking(db: &Database, session: Session) -> LagoResult<()> {
358→        let json = serde_json::to_string(&session)?;
359→        let txn = db
360→            .begin_write()
361→            .map_err(|e| LagoError::Journal(format!("begin_write failed: {e}")))?;
362→        {
363→            let mut table = txn
364→                .open_table(SESSIONS)
365→                .map_err(|e| LagoError::Journal(format!("open sessions table: {e}")))?;
366→            table
367→                .insert(session.session_id.as_str(), json.as_str())
368→                .map_err(|e| LagoError::Journal(format!("insert session: {e}")))?;
369→        }
370→        txn.commit()
371→            .map_err(|e| LagoError::Journal(format!("commit failed: {e}")))?;
372→        Ok(())
373→    }
374→
375→    /// Get a session by ID.
376→    fn get_session_blocking(db: &Database, session_id: &str) -> LagoResult<Option<Session>> {
377→        let txn = db
378→            .begin_read()
379→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
380→        let table = txn
381→            .open_table(SESSIONS)
382→            .map_err(|e| LagoError::Journal(format!("open sessions table: {e}")))?;
383→
384→        match table
385→            .get(session_id)
386→            .map_err(|e| LagoError::Journal(format!("get session: {e}")))?
387→        {
388→            Some(v) => {
389→                let session: Session = serde_json::from_str(v.value())?;
390→                Ok(Some(session))
391→            }
392→            None => Ok(None),
393→        }
394→    }
395→
396→    /// List all sessions.
397→    fn list_sessions_blocking(db: &Database) -> LagoResult<Vec<Session>> {
398→        let txn = db
399→            .begin_read()
400→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
401→        let table = txn
402→            .open_table(SESSIONS)
403→            .map_err(|e| LagoError::Journal(format!("open sessions table: {e}")))?;
404→
405→        let mut sessions = Vec::new();
406→        for item in table
407→            .iter()
408→            .map_err(|e| LagoError::Journal(format!("iter sessions: {e}")))?
409→        {
410→            let (_key, value) =
411→                item.map_err(|e| LagoError::Journal(format!("session item: {e}")))?;
412→            let json_str: &str = value.value();
413→            let session: Session = serde_json::from_str(json_str)?;
414→            sessions.push(session);
415→        }
416→        Ok(sessions)
417→    }
418→}
