  8→/// Query parameters for reading events.
  9→#[derive(Debug, Clone, Default)]
 10→pub struct EventQuery {
 11→    pub session_id: Option<SessionId>,
 12→    pub branch_id: Option<BranchId>,
 13→    pub after_seq: Option<SeqNo>,
 14→    pub before_seq: Option<SeqNo>,
 15→    pub limit: Option<usize>,
 16→}
 17→
 18→impl EventQuery {
 19→    pub fn new() -> Self {
 20→        Self::default()
 21→    }
 22→
 23→    pub fn session(mut self, id: SessionId) -> Self {
 24→        self.session_id = Some(id);
 25→        self
 26→    }
 27→
 28→    pub fn branch(mut self, id: BranchId) -> Self {
 29→        self.branch_id = Some(id);
 30→        self
 31→    }
 32→
 33→    pub fn after(mut self, seq: SeqNo) -> Self {
 34→        self.after_seq = Some(seq);
 35→        self
 36→    }
 37→
 38→    pub fn before(mut self, seq: SeqNo) -> Self {
 39→        self.before_seq = Some(seq);
