 27→/// Full agent session lifecycle: start → tool call → tool result → state patch → finish.
 28→/// Verifies that all events survive the Arcan → Lago → Arcan round trip and that
 29→/// the AppStateProjection correctly reconstructs conversation history and app state.
 30→#[tokio::test]
 31→async fn full_session_lifecycle_round_trip() {
 32→    let journal = open_journal();
 33→    let repo = Arc::new(LagoSessionRepository::new(journal.clone()));
 34→
 35→    let session_id = "e2e-session-1";
 36→
 37→    // Simulate a complete agent session
 38→    let events = vec![
 39→        AgentEvent::RunStarted {
 40→            run_id: "r1".into(),
 41→            session_id: session_id.into(),
 42→            provider: "anthropic".into(),
 43→            max_iterations: 10,
 44→        },
 45→        AgentEvent::IterationStarted {
 46→            run_id: "r1".into(),
 47→            session_id: session_id.into(),
 48→            iteration: 1,
 49→        },
 50→        AgentEvent::TextDelta {
 51→            run_id: "r1".into(),
 52→            session_id: session_id.into(),
 53→            iteration: 1,
 54→            delta: "Let me read ".into(),
 55→        },
 56→        AgentEvent::TextDelta {
 57→            run_id: "r1".into(),
 58→            session_id: session_id.into(),
 59→            iteration: 1,
 60→            delta: "that file for you.".into(),
 61→        },
 62→        AgentEvent::ToolCallRequested {
 63→            run_id: "r1".into(),
 64→            session_id: session_id.into(),
 65→            iteration: 1,
 66→            call: ToolCall {
 67→                call_id: "call-1".into(),
 68→                tool_name: "read_file".into(),
 69→                input: serde_json::json!({"path": "/tmp/test.txt"}),
 70→            },
 71→        },
 72→        AgentEvent::ToolCallCompleted {
 73→            run_id: "r1".into(),
 74→            session_id: session_id.into(),
 75→            iteration: 1,
 76→            result: ToolResultSummary {
 77→                call_id: "call-1".into(),
 78→                tool_name: "read_file".into(),
 79→                output: serde_json::json!({"content": "Hello, World!"}),
 80→            },
 81→        },
 82→        AgentEvent::StatePatched {
 83→            run_id: "r1".into(),
 84→            session_id: session_id.into(),
 85→            iteration: 1,
 86→            patch: StatePatch {
 87→                format: StatePatchFormat::MergePatch,
 88→                patch: serde_json::json!({"cwd": "/tmp", "last_file": "test.txt"}),
 89→                source: StatePatchSource::Tool,
 90→            },
 91→            revision: 1,
 92→        },
 93→        AgentEvent::TextDelta {
 94→            run_id: "r1".into(),
 95→            session_id: session_id.into(),
 96→            iteration: 2,
 97→            delta: "The file contains: Hello, World!".into(),
 98→        },
 99→        AgentEvent::RunFinished {
100→            run_id: "r1".into(),
101→            session_id: session_id.into(),
102→            reason: RunStopReason::Completed,
103→            total_iterations: 2,
104→            final_answer: Some("The file contains: Hello, World!".into()),
105→        },
106→    ];
107→
108→    // Write all events through the repository (Arcan → Lago journal)
109→    let events_clone = events.clone();
110→    tokio::task::spawn_blocking({
111→        let repo = repo.clone();
112→        move || {
113→            for event in events_clone {
114→                repo.append(AppendEvent {
115→                    session_id: session_id.to_string(),
116→                    branch_id: "main".to_string(),
117→                    parent_id: None,
118→                    event,
119→                })
120→                .expect("append should succeed");
121→            }
122→        }
123→    })
124→    .await
125→    .unwrap();
126→
127→    // Read back through the repository (Lago journal → Arcan events)
128→    let records = tokio::task::spawn_blocking({
129→        let repo = repo.clone();
130→        move || {
131→            repo.load_session(session_id, "main")
132→                .expect("load should succeed")
133→        }
134→    })
135→    .await
136→    .unwrap();
137→
138→    // Verify all mappable events came back
139→    assert_eq!(records.len(), 9, "all 9 events should round-trip");
140→
141→    // Verify event types in order
142→    assert!(matches!(records[0].event, AgentEvent::RunStarted { .. }));
143→    assert!(matches!(
144→        records[1].event,
145→        AgentEvent::IterationStarted { .. }
146→    ));
147→    assert!(matches!(records[2].event, AgentEvent::TextDelta { .. }));
148→    assert!(matches!(records[3].event, AgentEvent::TextDelta { .. }));
149→    assert!(matches!(
150→        records[4].event,
151→        AgentEvent::ToolCallRequested { .. }
152→    ));
153→    assert!(matches!(
154→        records[5].event,
155→        AgentEvent::ToolCallCompleted { .. }
156→    ));
157→    assert!(matches!(records[6].event, AgentEvent::StatePatched { .. }));
158→    assert!(matches!(records[7].event, AgentEvent::TextDelta { .. }));
159→    assert!(matches!(records[8].event, AgentEvent::RunFinished { .. }));
160→
161→    // Replay through AppStateProjection via the journal directly
162→    let session_id_lago = lago_core::SessionId::from(session_id.to_string());
163→    let branch_id = lago_core::BranchId::from("main");
164→    let query = lago_core::EventQuery::new()
165→        .session(session_id_lago)
166→        .branch(branch_id);
167→    let envelopes = journal.read(query).await.expect("read should succeed");
168→
169→    let mut projection = AppStateProjection::new();
170→    for envelope in &envelopes {
171→        projection
172→            .on_event(envelope)
173→            .expect("projection should succeed");
174→    }
175→
176→    // Verify reconstructed conversation history
177→    // The projection aggregates consecutive text deltas into a single assistant
178→    // message, so we get: assistant (aggregated deltas), tool result, assistant.
179→    let messages = projection.messages();
180→    assert_eq!(
181→        messages.len(),
182→        3,
183→        "should have 3 messages: 1 aggregated assistant, 1 tool, 1 assistant"
184→    );
185→
186→    // First message: aggregated text deltas from iteration 1
187→    assert_eq!(messages[0].content, "Let me read that file for you.");
188→    assert_eq!(messages[0].role, arcan_core::protocol::Role::Assistant);
189→
190→    // Second message: tool result
191→    assert_eq!(messages[1].role, arcan_core::protocol::Role::Tool);
192→    assert!(messages[1].content.contains("Hello, World!"));
193→
194→    // Third message: assistant text from iteration 2
195→    assert_eq!(messages[2].role, arcan_core::protocol::Role::Assistant);
196→    assert_eq!(messages[2].content, "The file contains: Hello, World!");
197→
198→    // Verify reconstructed app state
199→    let state = projection.state();
200→    assert_eq!(state.cwd(), Some("/tmp".to_string()));
201→}
