 40→fn unique_root(name: &str) -> PathBuf {
 41→    let nanos = SystemTime::now()
 42→        .duration_since(UNIX_EPOCH)
 43→        .map(|duration| duration.as_nanos())
 44→        .unwrap_or(0);
 45→    std::env::temp_dir().join(format!("{name}-{nanos}"))
 46→}
