 21→#[async_trait]
 22→pub trait EventStore: Send + Sync {
 23→    async fn append(&self, event: &EventRecord) -> Result<()>;
 24→    async fn read_from(
 25→        &self,
 26→        session_id: SessionId,
 27→        branch_id: Option<BranchId>,
 28→        from_sequence: u64,
 29→        limit: usize,
 30→    ) -> Result<Vec<EventRecord>>;
 31→    async fn latest_sequence(
 32→        &self,
 33→        session_id: SessionId,
 34→        branch_id: Option<BranchId>,
 35→    ) -> Result<u64>;
 36→}
 37→
 38→#[derive(Debug)]
 39→pub struct FileEventStore {
 40→    root: PathBuf,
 41→    write_locks: Mutex<HashMap<String, Arc<tokio::sync::Mutex<()>>>>,
 42→    sequence_cache: Mutex<HashMap<(String, String), u64>>,
 43→}
 44→
 45→impl FileEventStore {
 46→    pub fn new(root: impl Into<PathBuf>) -> Self {
 47→        Self {
 48→            root: root.into(),
 49→            write_locks: Mutex::new(HashMap::new()),
 50→            sequence_cache: Mutex::new(HashMap::new()),
 51→        }
 52→    }
 53→
 54→    fn file_path(&self, session_id: &SessionId) -> PathBuf {
 55→        self.root
 56→            .join("events")
 57→            .join(format!("{}.jsonl", session_id.as_str()))
 58→    }
 59→
 60→    async fn ensure_parent(path: &Path) -> Result<()> {
 61→        if let Some(parent) = path.parent() {
 62→            fs::create_dir_all(parent)
 63→                .await
 64→                .with_context(|| format!("failed to create events dir {parent:?}"))?;
 65→        }
 66→        Ok(())
 67→    }
 68→
 69→    fn lock_for(&self, session_id: &SessionId) -> Arc<tokio::sync::Mutex<()>> {
 70→        let mut guard = self.write_locks.lock();
 71→        guard
 72→            .entry(session_id.as_str().to_owned())
 73→            .or_insert_with(|| Arc::new(tokio::sync::Mutex::new(())))
 74→            .clone()
 75→    }
 76→
 77→    async fn scan_latest_sequence(path: &Path, branch_filter: Option<&BranchId>) -> Result<u64> {
 78→        if !fs::try_exists(path).await.unwrap_or(false) {
 79→            return Ok(0);
 80→        }
 81→
 82→        let file = OpenOptions::new().read(true).open(path).await?;
 83→        let mut reader = BufReader::new(file).lines();
 84→        let mut latest = 0_u64;
 85→
 86→        while let Some(line) = reader.next_line().await? {
 87→            if line.trim().is_empty() {
 88→                continue;
 89→            }
 90→            let event: EventRecord = serde_json::from_str(&line)
 91→                .with_context(|| format!("failed parsing event line in {path:?}"))?;
 92→            if let Some(branch) = branch_filter
 93→                && event.branch_id != *branch
 94→            {
 95→                continue;
 96→            }
 97→            latest = latest.max(event.sequence);
 98→        }
 99→        Ok(latest)
100→    }
101→
102→    fn cached_latest_sequence(&self, session_id: &SessionId, branch_id: &BranchId) -> Option<u64> {
103→        self.sequence_cache
104→            .lock()
105→            .get(&(
106→                session_id.as_str().to_owned(),
107→                branch_id.as_str().to_owned(),
108→            ))
109→            .copied()
110→    }
111→
112→    fn update_cached_sequence(&self, session_id: &SessionId, branch_id: &BranchId, latest: u64) {
113→        self.sequence_cache.lock().insert(
114→            (
115→                session_id.as_str().to_owned(),
116→                branch_id.as_str().to_owned(),
117→            ),
118→            latest,
119→        );
120→    }
121→}
122→
123→#[async_trait]
124→impl EventStore for FileEventStore {
125→    #[instrument(
126→        skip(self, event),
127→        fields(
128→            session_id = %event.session_id,
129→            branch = %event.branch_id,
130→            sequence = event.sequence
131→        )
132→    )]
133→    async fn append(&self, event: &EventRecord) -> Result<()> {
134→        let path = self.file_path(&event.session_id);
135→        Self::ensure_parent(&path).await?;
136→
137→        let lock = self.lock_for(&event.session_id);
138→        let _guard = lock.lock().await;
139→
140→        let latest = match self.cached_latest_sequence(&event.session_id, &event.branch_id) {
141→            Some(latest) => latest,
142→            None => {
143→                let latest = Self::scan_latest_sequence(&path, Some(&event.branch_id)).await?;
144→                self.update_cached_sequence(&event.session_id, &event.branch_id, latest);
145→                latest
146→            }
147→        };
148→
149→        let expected_sequence = latest.saturating_add(1);
150→        if event.sequence != expected_sequence {
151→            warn!(
152→                expected_sequence,
153→                actual_sequence = event.sequence,
154→                "sequence conflict while appending event"
155→            );
156→            bail!(
157→                "sequence conflict for session {}: expected {}, got {}",
158→                event.session_id,
159→                expected_sequence,
160→                event.sequence
161→            );
162→        }
163→
164→        let mut file = OpenOptions::new()
165→            .create(true)
166→            .append(true)
167→            .open(&path)
168→            .await
169→            .with_context(|| format!("failed opening event log {path:?}"))?;
170→
171→        let line = serde_json::to_string(event).context("failed serializing event")?;
172→        file.write_all(line.as_bytes()).await?;
173→        file.write_all(b"\n").await?;
174→        file.flush().await?;
175→        self.update_cached_sequence(&event.session_id, &event.branch_id, event.sequence);
176→        debug!("event appended to store");
177→        Ok(())
178→    }
179→
180→    #[instrument(
181→        skip(self),
182→        fields(session_id = %session_id, branch = ?branch_id.as_ref().map(|b| b.as_str()), from_sequence, limit)
183→    )]
184→    async fn read_from(
185→        &self,
186→        session_id: SessionId,
187→        branch_id: Option<BranchId>,
188→        from_sequence: u64,
189→        limit: usize,
190→    ) -> Result<Vec<EventRecord>> {
191→        let path = self.file_path(&session_id);
192→        if !fs::try_exists(&path).await.unwrap_or(false) {
193→            return Ok(Vec::new());
194→        }
195→
196→        let file = OpenOptions::new().read(true).open(&path).await?;
197→        let mut reader = BufReader::new(file).lines();
198→        let mut out = Vec::new();
199→
200→        while let Some(line) = reader.next_line().await? {
201→            if line.trim().is_empty() {
202→                continue;
203→            }
204→            let event: EventRecord = serde_json::from_str(&line)
205→                .with_context(|| format!("failed parsing event line in {path:?}"))?;
206→            if let Some(branch) = &branch_id
207→                && event.branch_id != *branch
208→            {
209→                continue;
210→            }
211→            if event.sequence >= from_sequence {
212→                out.push(event);
213→            }
214→            if out.len() >= limit {
215→                break;
216→            }
217→        }
218→        debug!(count = out.len(), "events loaded from store");
219→        Ok(out)
220→    }
221→
222→    #[instrument(
223→        skip(self),
224→        fields(session_id = %session_id, branch = ?branch_id.as_ref().map(|b| b.as_str()))
225→    )]
226→    async fn latest_sequence(
227→        &self,
228→        session_id: SessionId,
229→        branch_id: Option<BranchId>,
230→    ) -> Result<u64> {
231→        let branch = branch_id.unwrap_or_default();
232→        if let Some(latest) = self.cached_latest_sequence(&session_id, &branch) {
233→            return Ok(latest);
234→        }
235→
236→        let path = self.file_path(&session_id);
237→        let latest = Self::scan_latest_sequence(&path, Some(&branch)).await?;
238→        self.update_cached_sequence(&session_id, &branch, latest);
239→        debug!(latest, "latest sequence resolved");
240→        Ok(latest)
241→    }
242→}
