255→    pub fn publish(&self, event: EventRecord) {
256→        let _ = self.sender.send(event);
257→    }
258→
259→    pub fn subscribe(&self) -> broadcast::Receiver<EventRecord> {
260→        self.sender.subscribe()
261→    }
262→
