268→#[derive(Clone)]
269→pub struct EventJournal {
270→    store: Arc<dyn EventStore>,
271→    stream: EventStreamHub,
272→}
273→
274→impl EventJournal {
275→    pub fn new(store: Arc<dyn EventStore>, stream: EventStreamHub) -> Self {
276→        Self { store, stream }
277→    }
278→
279→    #[instrument(
280→        skip(self, event),
281→        fields(
282→            session_id = %event.session_id,
283→            branch = %event.branch_id,
284→            sequence = event.sequence
285→        )
286→    )]
287→    pub async fn append_and_publish(&self, event: EventRecord) -> Result<()> {
288→        self.store.append(&event).await?;
289→        self.stream.publish(event);
290→        debug!("event published to stream");
291→        Ok(())
292→    }
293→
294→    pub async fn read_from(
295→        &self,
296→        session_id: SessionId,
297→        branch_id: Option<BranchId>,
298→        from_sequence: u64,
299→        limit: usize,
300→    ) -> Result<Vec<EventRecord>> {
301→        self.store
302→            .read_from(session_id, branch_id, from_sequence, limit)
303→            .await
304→    }
305→
306→    pub async fn latest_sequence(
307→        &self,
308→        session_id: SessionId,
309→        branch_id: Option<BranchId>,
310→    ) -> Result<u64> {
311→        self.store.latest_sequence(session_id, branch_id).await
312→    }
313→
314→    pub fn subscribe(&self) -> broadcast::Receiver<EventRecord> {
315→        self.stream.subscribe()
316→    }
317→}
