319→#[async_trait]
320→impl EventStorePort for EventJournal {
321→    async fn append(&self, event: EventRecord) -> std::result::Result<EventRecord, KernelError> {
322→        self.append_and_publish(event.clone())
323→            .await
324→            .map_err(to_kernel_error)?;
325→        Ok(event)
326→    }
327→
328→    async fn read(
329→        &self,
330→        session_id: SessionId,
331→        branch_id: BranchId,
332→        from_sequence: u64,
333→        limit: usize,
334→    ) -> std::result::Result<Vec<EventRecord>, KernelError> {
335→        self.read_from(session_id, Some(branch_id), from_sequence, limit)
336→            .await
337→            .map_err(to_kernel_error)
338→    }
339→
340→    async fn head(
341→        &self,
342→        session_id: SessionId,
343→        branch_id: BranchId,
344→    ) -> std::result::Result<u64, KernelError> {
345→        self.latest_sequence(session_id, Some(branch_id))
346→            .await
347→            .map_err(to_kernel_error)
348→    }
349→
350→    async fn subscribe(
351→        &self,
352→        session_id: SessionId,
353→        branch_id: BranchId,
354→        after_sequence: u64,
355→    ) -> std::result::Result<EventRecordStream, KernelError> {
356→        // Replay a bounded prefix to support resume semantics before tailing.
357→        let replay = self
358→            .read_from(
359→                session_id.clone(),
360→                Some(branch_id.clone()),
361→                after_sequence.saturating_add(1),
362→                10_000,
363→            )
364→            .await
365→            .map_err(to_kernel_error)?;
366→
367→        let mut receiver = EventJournal::subscribe(self);
368→        let stream = async_stream::try_stream! {
369→            for event in replay {
370→                if event.session_id == session_id
371→                    && event.branch_id == branch_id
372→                    && event.sequence > after_sequence
373→                {
374→                    yield event;
375→                }
376→            }
377→
378→            loop {
379→                match receiver.recv().await {
380→                    Ok(event) => {
381→                        if event.session_id == session_id
382→                            && event.branch_id == branch_id
383→                            && event.sequence > after_sequence
384→                        {
385→                            yield event;
386→                        }
387→                    }
388→                    Err(tokio::sync::broadcast::error::RecvError::Lagged(skipped)) => {
389→                        warn!(skipped, "event subscription lagged; dropping stale frames");
390→                    }
391→                    Err(tokio::sync::broadcast::error::RecvError::Closed) => break,
392→                }
393→            }
394→        };
395→
396→        Ok(Box::pin(stream))
397→    }
398→}
